### `apps/client/src/layers/features/relay/model/use-adapter-card-dialogs.ts` (~60 lines)

Custom hook managing which dialog is open and for which adapter instance:

```tsx
import { useState } from 'react';
import type { AdapterBinding } from '@dorkos/shared/relay-schemas';

interface DialogState {
  removeTarget: { instanceId: string; name: string } | null;
  eventsTarget: { instanceId: string } | null;
  bindingTarget: { mode: 'create' | 'edit'; adapterId: string; binding?: AdapterBinding } | null;
}

/** Manages dialog open/close state for AdapterCard actions hosted at the ConnectionsTab level. */
export function useAdapterCardDialogs() {
  const [state, setState] = useState<DialogState>({
    removeTarget: null,
    eventsTarget: null,
    bindingTarget: null,
  });

  return {
    ...state,
    openRemove: (instanceId: string, name: string) =>
      setState((s) => ({ ...s, removeTarget: { instanceId, name } })),
    closeRemove: () => setState((s) => ({ ...s, removeTarget: null })),
    openEvents: (instanceId: string) => setState((s) => ({ ...s, eventsTarget: { instanceId } })),
    closeEvents: () => setState((s) => ({ ...s, eventsTarget: null })),
    openBindingCreate: (adapterId: string) =>
      setState((s) => ({ ...s, bindingTarget: { mode: 'create', adapterId } })),
    openBindingEdit: (adapterId: string, binding: AdapterBinding) =>
      setState((s) => ({ ...s, bindingTarget: { mode: 'edit', adapterId, binding } })),
    closeBinding: () => setState((s) => ({ ...s, bindingTarget: null })),
  };
}
```

## Files to Modify

### `apps/client/src/layers/features/relay/ui/AdapterCard.tsx` (462 -> ~120 lines)

Become a display-only orchestrator. Retains data fetching hooks (`useBindings()`, `useRegisteredAgents()`) and computed values (binding filtering, agent lookup, status dot class computation). Delegates rendering to the three sub-components. No longer contains dialog state or dialog rendering.

New prop interface adds intent callbacks for dialogs:
```tsx
interface AdapterCardProps {
  instance: CatalogInstance;
  manifest: AdapterManifest;
  onToggle: (enabled: boolean) => void;
  onConfigure: () => void;
  onRemove: () => void;
  onShowEvents: (instanceId: string) => void;
  onEditBinding: (binding: AdapterBinding) => void;
  onRemoveConfirm: (instanceId: string, name: string) => void;
  onAddBinding: (instanceId: string, adapterId: string) => void;
}
```

The component structure becomes:
```tsx
export function AdapterCard({ instance, manifest, onToggle, onConfigure, onRemove, onShowEvents, onEditBinding, onRemoveConfirm, onAddBinding }: AdapterCardProps) {
  // Data hooks stay here — shared across sub-components
  const { data: allBindings = [] } = useBindings();
  const { data: agentsData } = useRegisteredAgents();
  const createBinding = useCreateBinding();
  // ... binding computation, agent lookup, status dot class

  return (
    <div className={cn('shadow-soft hover:shadow-elevated rounded-xl border p-5 transition-shadow', isBuiltinClaude && 'border-dashed')}>
      <AdapterCardHeader
        manifest={manifest}
        instance={instance}
        primaryName={primaryName}
        secondaryName={secondaryName}
        statusDotClass={statusDotClass}
        onToggle={onToggle}
        onShowEvents={() => onShowEvents(instance.id)}
        onConfigure={onConfigure}
        onRemove={() => onRemoveConfirm(instance.id, primaryName)}
        onAddBinding={() => onAddBinding(instance.id, instance.id)}
        isBuiltinClaude={isBuiltinClaude}
      />
      <AdapterCardBindings
        instance={instance}
        manifest={manifest}
        isBuiltinClaude={isBuiltinClaude}
        boundAgentRows={boundAgentRows}
        adapterBindings={adapterBindings}
        totalAgentCount={totalAgentCount}
        isConnected={isConnected}
        hasBindings={hasBindings}
        onEditBinding={(binding) => onEditBinding(binding)}
        onQuickBind={handleQuickBind}
        onAdvancedBind={() => onAddBinding(instance.id, instance.id)}
        createBindingPending={createBinding.isPending}
      />
      <AdapterCardError instance={instance} />
    </div>
  );
}
```

The `handleQuickBind` function stays in AdapterCard since it uses `createBinding.mutateAsync` and the quick-bind toast pattern. The remove/update/delete binding mutations move to ConnectionsTab where the dialogs live.

