### `apps/client/src/layers/features/relay/__tests__/use-adapter-setup-form.test.ts` (~100 lines)

Pure logic tests for the extracted hook utilities:

```tsx
import { describe, it, expect } from 'vitest';
import { unflattenConfig, initializeValues, generateDefaultId } from '../model/use-adapter-setup-form';
import type { AdapterManifest } from '@dorkos/shared/relay-schemas';

const baseManifest: AdapterManifest = {
  type: 'telegram',
  displayName: 'Telegram',
  description: 'Telegram adapter',
  iconEmoji: '📨',
  category: 'messaging',
  builtin: false,
  configFields: [
    { key: 'token', label: 'Bot Token', type: 'password', required: true },
    { key: 'chatId', label: 'Chat ID', type: 'text', required: false, default: '' },
    { key: 'enabled', label: 'Auto-start', type: 'boolean', required: false, default: true },
  ],
  multiInstance: false,
};

describe('unflattenConfig', () => {
  it('converts dot-notation keys to nested object', () => {
    const result = unflattenConfig({ 'inbound.subject': 'hello', 'inbound.format': 'json', 'outbound.subject': 'world' });
    expect(result).toEqual({ inbound: { subject: 'hello', format: 'json' }, outbound: { subject: 'world' } });
  });

  it('handles non-nested keys', () => {
    const result = unflattenConfig({ token: 'abc123', chatId: '456' });
    expect(result).toEqual({ token: 'abc123', chatId: '456' });
  });

  it('handles empty object', () => {
    expect(unflattenConfig({})).toEqual({});
  });
});

describe('initializeValues', () => {
  it('returns defaults for new adapters', () => {
    const values = initializeValues(baseManifest);
    expect(values).toEqual({ token: '', chatId: '', enabled: true });
  });

  it('uses existing config for edit mode', () => {
    const values = initializeValues(baseManifest, { token: 'real-token', chatId: '123', enabled: false });
    expect(values.chatId).toBe('123');
    expect(values.enabled).toBe(false);
  });

  it('uses password sentinel for existing password fields', () => {
    const values = initializeValues(baseManifest, { token: 'secret' });
    expect(values.token).toBe('***');
  });

  it('returns boolean false as default for boolean fields without default', () => {
    const manifest = { ...baseManifest, configFields: [{ key: 'flag', label: 'Flag', type: 'boolean' as const, required: false }] };
    const values = initializeValues(manifest);
    expect(values.flag).toBe(false);
  });
});

describe('generateDefaultId', () => {
  it('returns type as ID when no conflicts', () => {
    expect(generateDefaultId(baseManifest)).toBe('telegram');
  });

  it('returns type-2 when type is taken', () => {
    expect(generateDefaultId(baseManifest, ['telegram'])).toBe('telegram-2');
  });

  it('returns type-3 when type and type-2 are taken', () => {
    expect(generateDefaultId(baseManifest, ['telegram', 'telegram-2'])).toBe('telegram-3');
  });
});
```

