  const unboundAgents = agents.filter((a) => !boundAgentIds.has(a.id));

  // ... use unboundAgents instead of agents in the CommandList map

  // Update CommandEmpty to show contextual message:
  <CommandEmpty>
    {agents.length === 0 ? 'No agents registered' : 'All agents bound'}
  </CommandEmpty>
